//! rf-gossip-bridge — protocol69 RF-to-gossip bridge daemon
//! (docs/R1_MESH_PROTOCOL69.md section 1 / step 4).
//!
//! Listens for protocol69 RF beacons, validates each FAIL-CLOSED, and injects the
//! advertised node into a running fat-station's stream-2010 gossip registry as a direct
//! heartbeat (UDP). This is the least-invasive integration: the SDR dependency stays OUT
//! of fat-station; the bridge runs on any WiFi-connected host (or, once the USB-OTG
//! rtl-sdr path is proven, on an R1 itself).
//!
//! Beacon SOURCES:
//!   --source selftest  emit one canonical beacon for --node-id/--stage/--data-host. A
//!                      wiring smoke test: proves bridge -> gossip -> /mesh/peers with no
//!                      radio. (default)
//!   --source file      read newline-delimited JSON beacons from --beacon-file (one
//!                      `Protocol69RfBeacon` per line); re-sent every --interval-secs.
//!   --source rtlsdr    NOT BUILT — needs the NESDR/Pluto demod path wired on this host
//!                      (and, for on-device, the R1 USB-OTG driver probe, step 5). Exits.
//!
//! Re-sends on --interval-secs so injected nodes stay live within the gossip eviction
//! window; --once sends a single round. Injected nodes appear in the target's
//! /mesh/peers but enter the /chain routing pool only after the normal qspec admission
//! (note_direct inserts them as admitted:false).
use std::net::UdpSocket;
use std::time::Duration;

use distributed_inference::rf_beacon::Protocol69RfBeacon;

fn now_ms() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0)
}

fn send_beacon(sock: &UdpSocket, target: &str, b: &Protocol69RfBeacon, seq: u32) {
    match b.to_gossip_frame(seq) {
        Ok(frame) => match sock.send_to(&frame, target) {
            Ok(_) => eprintln!(
                "[rf-bridge] injected {} stage {}..{} ({}) -> {target} (seq {seq})",
                b.node_id, b.stage_lo, b.stage_hi, b.host
            ),
            Err(e) => eprintln!("[rf-bridge] send to {target} failed: {e}"),
        },
        // Fail-closed: a drifted/forged envelope never reaches the registry.
        Err(e) => eprintln!("[rf-bridge] DROP {} (fail-closed): {e}", b.node_id),
    }
}

fn load_beacons_file(path: &str) -> Vec<Protocol69RfBeacon> {
    let txt = std::fs::read_to_string(path).unwrap_or_else(|e| {
        eprintln!("[rf-bridge] cannot read {path}: {e}");
        std::process::exit(4);
    });
    txt.lines()
        .map(str::trim)
        .filter(|l| !l.is_empty())
        .filter_map(|l| {
            Protocol69RfBeacon::decode(l.as_bytes()).or_else(|| {
                eprintln!("[rf-bridge] skipping unparseable beacon line");
                None
            })
        })
        .collect()
}

fn main() {
    let mut target = String::new();
    let mut source = String::from("selftest");
    let mut beacon_file = String::new();
    let mut interval_secs: u64 = 5;
    let mut once = false;
    // selftest beacon defaults
    let mut node_id = String::from("r1-rf");
    let mut model_id = String::from("qwen2");
    let mut stage = String::from("12..24");
    let mut role = String::from("exit");
    let mut data_host = String::from("10.0.0.240");
    let mut data_port: u16 = 8090;
    let mut gossip_port: u16 = 9090;

    let mut args = std::env::args().skip(1);
    while let Some(a) = args.next() {
        match a.as_str() {
            "--gossip-target" => target = args.next().unwrap_or_default(),
            "--source" => source = args.next().unwrap_or_default(),
            "--beacon-file" => beacon_file = args.next().unwrap_or_default(),
            "--interval-secs" => {
                interval_secs = args.next().and_then(|v| v.parse().ok()).unwrap_or(5)
            }
            "--once" => once = true,
            "--node-id" => node_id = args.next().unwrap_or_default(),
            "--model-id" => model_id = args.next().unwrap_or_default(),
            "--stage" => stage = args.next().unwrap_or_default(),
            "--role" => role = args.next().unwrap_or_default(),
            "--data-host" => data_host = args.next().unwrap_or_default(),
            "--data-port" => data_port = args.next().and_then(|v| v.parse().ok()).unwrap_or(8090),
            "--gossip-port" => {
                gossip_port = args.next().and_then(|v| v.parse().ok()).unwrap_or(9090)
            }
            other => {
                eprintln!("rf-gossip-bridge: unknown arg {other}");
                std::process::exit(2);
            }
        }
    }
    if target.is_empty() {
        eprintln!(
            "usage: rf-gossip-bridge --gossip-target IP:PORT \
             [--source selftest|file|rtlsdr] [--beacon-file PATH] \
             [--interval-secs N] [--once]"
        );
        std::process::exit(2);
    }

    let beacons: Vec<Protocol69RfBeacon> = match source.as_str() {
        "rtlsdr" => {
            eprintln!(
                "[rf-bridge] --source rtlsdr is NOT BUILT: the NESDR/Pluto demod path is \
                 not wired (R1_MESH_PROTOCOL69.md step 5 — probe USB-OTG rtl-sdr on the R1 \
                 first). Use --source file or selftest."
            );
            std::process::exit(3);
        }
        "file" => {
            if beacon_file.is_empty() {
                eprintln!("[rf-bridge] --source file requires --beacon-file PATH");
                std::process::exit(2);
            }
            load_beacons_file(&beacon_file)
        }
        "selftest" => {
            let (lo, hi) = stage.split_once("..").unwrap_or(("12", "24"));
            vec![Protocol69RfBeacon::canonical(
                node_id,
                model_id,
                lo.parse().unwrap_or(12),
                hi.parse().unwrap_or(24),
                role,
                data_host,
                data_port,
                gossip_port,
                now_ms(),
                1,
            )]
        }
        other => {
            eprintln!("[rf-bridge] unknown --source {other}");
            std::process::exit(2);
        }
    };

    if beacons.is_empty() {
        eprintln!("[rf-bridge] no beacons to inject");
        std::process::exit(3);
    }

    let sock = UdpSocket::bind("0.0.0.0:0").unwrap_or_else(|e| {
        eprintln!("[rf-bridge] bind failed: {e}");
        std::process::exit(4);
    });
    eprintln!(
        "[rf-bridge] {} beacon(s) -> gossip {target}, source={source}, interval={interval_secs}s, once={once}",
        beacons.len()
    );

    let mut seq: u32 = 0;
    loop {
        for b in &beacons {
            send_beacon(&sock, &target, b, seq);
            seq = seq.wrapping_add(1);
        }
        if once {
            break;
        }
        std::thread::sleep(Duration::from_secs(interval_secs.max(1)));
    }
}
